const threshold = parseInt($env.RISK_CRITICAL_SCORE || 15, 10);
const items = $input.all().map(i => {
  const d = i.json;
  if (d.status === 'resolved' || d.status === 'closed') return null;
  const P = parseInt(d.probability || 1, 10), I = parseInt(d.impact || 1, 10);
  const score = P * I;
  return { ...d, risk_score: score, severity: score >= threshold ? 'critical' : score >= 10 ? 'high' : score >= 5 ? 'medium' : 'low' };
}).filter(Boolean);
const critical = items.filter(r => r.severity === 'critical');
const high = items.filter(r => r.severity === 'high');
return [{ json: { week: new Date().toISOString().slice(0,10), total: items.length, critical_count: critical.length, high_count: high.length, items: items.sort((a,b)=>b.risk_score-a.risk_score), critical, high } }];

